package com.cognizant.ems.repository; import java.util.*; import org.springframework.data.jpa.repository.*; import org.springframework.data.repository.query.*; import com.cognizant.ems.model.*;
public interface EmployeeRepository extends JpaRepository<Employee,Long> {List<Employee> findByNameContainingIgnoreCase(String name);Optional<Employee> findByEmail(String email);@Query("select e from Employee e join fetch e.department where e.department.id=:departmentId")List<Employee> findWithDepartment(@Param("departmentId")Long departmentId);@Query("select avg(e.salary) from Employee e where e.department.id=:id")Double averageSalary(@Param("id")Long id);@Modifying @Query("update Employee e set e.salary=e.salary*:factor where e.department.id=:id")int increaseSalary(@Param("id")Long id,@Param("factor")double factor);}
